import re

def identify_tracking_number(tracking_no: str) -> str:
    tracking_no = tracking_no.strip().upper()
    '''
    1. Check AWB Number (Air Waybill)
        Format: 3-digit airline prefix + 8-digit serial (total 11 digits).    
        Example: 07112345678, 23598765432.    
        Sometimes written as 071-12345678.
    '''
    if re.match(r"^\d{3}[- ]?\d{8}$", tracking_no):
        return "AWB Number"

    '''
    2. Check Container Number
        Format: 4 letters (owner code + equipment category) + 6 digits + 1 check digit.
        Example: MSCU1234567, CMAU7654321.
        Always 11 characters: ^[A-Z]{4}\d{7}$.
    '''
    if re.match(r"^[A-Z]{4}\d{7}$", tracking_no):
        return "Container Number"

    '''
    3. Check MBL Number (Master Bill of Lading) (heuristic: alphanumeric 8–12 chars, not AWB/Container)
        No strict global standard, depends on shipping line.
        Often alphanumeric, 8–12 characters, starting with carrier code (e.g. OOLU123456789, MAEU1234567).
        We usually differentiate it by not matching AWB or container, but being longer alphanumeric (>=8).
    '''
    if re.match(r"^[A-Z0-9]{8,12}$", tracking_no):
        return "MBL Number"

    '''
    4. Otherwise assume Line Booking Number
        Issued by shipping line when booking a shipment.
        Can be pure numbers or alphanumeric, typically 6–12 chars.
        Often looks similar to MBL but may be shorter.
        We fallback here if it’s alphanumeric but doesn’t match strict AWB/Container.
    '''
    return "Line Booking Number"


